import { beforeEach, describe, expect, it } from "vitest";

import { POST } from "./route";
import {
  clearSignups,
  countSignups,
  listSignups,
} from "../../../lib/db/client";

function postSignup(body: unknown): Promise<Response> {
  const init: RequestInit = {
    method: "POST",
    headers: { "content-type": "application/json" },
    body: typeof body === "string" ? body : JSON.stringify(body),
  };
  return POST(new Request("http://localhost:3000/api/signup", init));
}

describe("POST /api/signup (CTO contract)", () => {
  beforeEach(() => clearSignups());

  it("queues a valid signup and returns { id, status: 'queued' }", async () => {
    const res = await postSignup({ email: "founder@indie.com" });
    expect(res.status).toBe(200);
    const json = await res.json();
    expect(json.status).toBe("queued");
    expect(typeof json.id).toBe("string");
    expect(json.id).toMatch(
      /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/,
    );
    expect(countSignups()).toBe(1);
  });

  it("is idempotent on lowercased email — second submit returns the original id with status: 'duplicate'", async () => {
    const first = await postSignup({ email: "founder@indie.com" });
    const firstJson = await first.json();
    const second = await postSignup({ email: "FOUNDER@INDIE.COM" });
    expect(second.status).toBe(200);
    const secondJson = await second.json();
    expect(secondJson.status).toBe("duplicate");
    expect(secondJson.id).toBe(firstJson.id);
    expect(countSignups()).toBe(1);
  });

  it("returns 400 for a malformed email", async () => {
    const res = await postSignup({ email: "not-an-email" });
    expect(res.status).toBe(400);
    const json = await res.json();
    expect(json.error).toMatch(/email/);
  });

  it("returns 400 for a request body that is not valid JSON", async () => {
    const res = await postSignup("this is not json");
    expect(res.status).toBe(400);
    const json = await res.json();
    expect(json.error).toMatch(/JSON/);
  });

  it("preserves a custom source", async () => {
    const res = await postSignup({ email: "a@b.com", source: "hn-launch" });
    expect(res.status).toBe(200);
    const stored = listSignups()[0];
    expect(stored.source).toBe("hn-launch");
  });

  it("defaults source to 'landing-v1' when missing or whitespace-only", async () => {
    await postSignup({ email: "default@source.com" });
    await postSignup({ email: "empty@source.com", source: "   " });
    const all = listSignups();
    expect(all[0].source).toBe("landing-v1");
    expect(all[1].source).toBe("landing-v1");
  });
});
